mapper.select:
SELECT dl.id AS logger_id, ds.id AS sensor_id, ds.code AS sensor_code, ds.sensor_type_id, dsts.min_gauge, dsts.max_gauge, ds.location, dl.cycle_check AS cycle_check FROM dain_logger dl JOIN dain_sensor ds ON ds.logger_id = dl.id JOIN dain_sensor_type_setting dsts ON dsts.place_id = ds.place_id AND dsts.sensor_type_id = ds.sensor_type_id WHERE dl.code = #{loggerCode}
AND ds.sensor_type_id = #{sensorTypeId}
AND dsts.hidden = false ORDER BY ds.code

SELECT d.measured_at, d.displace_val, d.changed_val, dsts.criteria_val1, dsts.criteria_val2, dsts.criteria_val3, ds.sensor_type_id FROM dain_sensor ds JOIN dain_sensor_type_setting dsts ON dsts.place_id = ds.place_id AND dsts.sensor_type_id = ds.sensor_type_id JOIN data_${placeCode} d ON d.sensor_id = ds.id WHERE ds.id = #{sensorId} AND d.measured_at >= #{start} AND d.measured_at <= #{end}
AND d.is_hourly = true
AND ds.used = true ORDER BY d.measured_at

	SELECT
		DATE_FORMAT(measured_at, '%Y-%m-%d %H:%i:%s') AS measured_at,
		ROUND(correction_val, 3) AS correction_val,
		ROUND(angle_val, 3) AS angle_val,
		ROUND(displace_val, 3) AS displace_val,
		ROUND(changed_val , 3) AS changed_val
	FROM data_${placeCode}
	WHERE
		sensor_id = #{sensorId}
		AND measured_at >= #{start}
		AND measured_at <= #{end}

			AND is_hourly = true

		AND used = true
	ORDER BY
		measured_at

    	DESC LIMIT #{limit} OFFSET #{offset}

SELECT
    @runtot := IFNULL(ROUND(SUM(changed_val), 3), 0)
FROM data_${placeCode}
WHERE
    sensor_id = #{sensorId}
    AND used = true
    AND measured_at <= #{start}

SELECT final.* FROM ( SELECT t.measurement_date, t.avg_changed_val, t.max_changed_val, t.record_count, t.today_changed_sum, t.sensor_type_id, @runtot := ROUND(@runtot + t.today_changed_sum, 3) AS current_runtot, IF(t.sensor_type_id = 25, @runtot, 0) AS total_changed_sum FROM ( SELECT DATE(d.measured_at) AS measurement_date, ds.sensor_type_id, -- 💡 센서 타입 ID를 여기서 가져와 t 서브쿼리로 전달 ROUND(AVG(d.changed_val), 3) AS avg_changed_val, ROUND(MAX(d.changed_val), 3) AS max_changed_val, COUNT(*) AS record_count, IF(ds.sensor_type_id = 25, ROUND(SUM(d.changed_val), 3), 0) AS today_changed_sum FROM dain_sensor ds JOIN dain_sensor_type_setting dsts ON dsts.place_id = ds.place_id AND dsts.sensor_type_id = ds.sensor_type_id JOIN data_${placeCode} d ON d.sensor_id = ds.id WHERE ds.id = #{sensorId} AND d.used = true AND d.measured_at >= #{start} AND d.measured_at <= #{end} GROUP BY DATE(d.measured_at) ORDER BY measurement_date ASC ) AS t ORDER BY t.measurement_date ASC ) AS final
ORDER BY final.measurement_date ASC
ORDER BY final.measurement_date DESC LIMIT #{limit} OFFSET #{offset}
